mapper.select:

WHERE b.tenant_id = #{tenantId}
  AND b.del_flag = '0'

    AND (b.business_name LIKE CONCAT('%', #{businessName}, '%')
        OR b.business_code LIKE CONCAT('%', #{businessName}, '%'))


    AND b.status = #{status}

ORDER BY b.create_time DESC


WHERE b.tenant_id = #{tenantId}
  AND b.del_flag = '0'

    AND b.status = #{status}

ORDER BY b.business_name ASC, b.id ASC

SELECT *
FROM ai_report_data_business_definition
WHERE tenant_id = #{tenantId}
  AND business_code = #{businessCode}
  AND del_flag = '0'
LIMIT 1
